215	uint64_t JavaVerify::FindSuperMethodToCall(art::ArtMethod& method, uint16_t dex_method_idx) {
216	    uint64_t result = 0;
217	    art::mirror::Class thiz = method.GetDeclaringClass();
218	    art::mirror::Class super = thiz.GetSuperClass();
219	
220	    art::DexFile& dex_file = thiz.GetDexFile();
221	    art::dex::MethodId mid = dex_file.GetMethodId(dex_method_idx);
222	
223	    std::string name;
224	    name.append(dex_file.GetMethodName(mid));
225	    name.append(dex_file.PrettyMethodParameters(mid));
226	
227	    std::string descriptor;
228	    art::AppendPrettyDescriptor(dex_file.GetMethodDeclaringClassDescriptor(mid), &descriptor);
229	    java::lang::Class resolve = java::lang::Class::forName(descriptor.c_str());
230	    art::mirror::Class resolve_class = resolve.thiz();
231	
232	    auto has_super_method = [&](art::ArtMethod& super_method) -> bool {
233	        std::string super_method_pretty;
234	        super_method_pretty.append(super_method.GetName());
235	        super_method_pretty.append(super_method.PrettyParameters());
236	        if (super_method_pretty == name) {
237	            result = super_method.Ptr();
238	            return true;
239	        }
240	        return false;
241	    };
242	
243	    if (resolve_class.Ptr() && resolve_class.IsInterface()) {
244	        art::mirror::IfTable& iftable = thiz.GetIfTable();
245	        int32_t ifcount = (iftable.Ptr() && iftable.IsValid()) ? iftable.Count() : 0;
246	        if (ifcount) {
247	            for (int i = 0; i < ifcount; ++i) {
248	                art::mirror::Class interface = iftable.GetInterface(i);
249	                Android::ForeachArtMethods(interface, has_super_method);
250	                if (result) break;
251	            }
252	        }
253	    }
254	
255	    if (!result) {
256	        do {
257	            Android::ForeachArtMethods(super, has_super_method);
258	            if (result) break;
259	            super = super.GetSuperClass();
260	        } while (super.Ptr());
261	    }
262	    return result;
263	}
264	
265	void JavaVerify::verifyMethods() {
266	    if (!(options & CHECK_FULL_REUSE_DEX_PC_PTR))
267	        return;
268	
269	    std::unordered_map<uint64_t, uint64_t> dex_pc_ptrs;
270	    std::unordered_map<uint64_t, std::vector<uint64_t>> reuse_dexpc_method;
271	    for (auto& value : methods) {
272	        uint64_t method = value.first;
273	        uint64_t dex_pc_ptr = value.second;
274	
275	        if (!dex_pc_ptrs.count(dex_pc_ptr)) {
276	            dex_pc_ptrs.insert(std::pair<uint64_t, uint64_t>(dex_pc_ptr, method));
277	        } else {
278	            auto it = reuse_dexpc_method.find(dex_pc_ptr);
279	            if (it == reuse_dexpc_method.end()) {
280	                std::vector<uint64_t> tmp_methods;
281	                tmp_methods.push_back(dex_pc_ptrs[dex_pc_ptr]);
282	                tmp_methods.push_back(method);
283	                reuse_dexpc_method.insert(std::pair<uint64_t, std::vector<uint64_t>>(dex_pc_ptr, tmp_methods));
284	            } else {
285	                it->second.push_back(method);
286	            }
287	        }
288	    }
289	
290	    for (auto& entry : reuse_dexpc_method) {
291	        art::ArtMethod tmp = entry.second[0];
292	        art::mirror::Class thiz = tmp.GetDeclaringClass();
293	        art::DexFile& dex_file = thiz.GetDexFile();
294	
295	        art::dex::CodeItem item = tmp.GetCodeItem();
296	        api::MemoryRef coderef = item.Ptr() + item.code_offset_;
297	        api::MemoryRef endref = coderef.Ptr() + (item.insns_count_ << 1);
298	
299	        bool maybe_warn = false;
300	        std::vector<uint16_t> super_methods;
301	        while (coderef < endref) {
302	            uint8_t op = art::Dexdump::GetDexOp(coderef);
303	            if (op == DEXOP::INVOKE_SUPER || op == DEXOP::INVOKE_SUPER_RANGE) {
304	                std::string super;
305	                uint16_t code1 = coderef.value16Of(2);
306	                // art::dex::MethodId mid = dex_file.GetMethodId(code1);
307	                // super.append(dex_file.GetMethodName(mid));
308	                // super.append(dex_file.PrettyMethodParameters(mid));
309	                super_methods.push_back(code1);
310	                maybe_warn = true;
311	            }
312	            coderef.MovePtr(art::Dexdump::GetDexInstSize(coderef));
313	        }
314	
315	        if (maybe_warn) {
316	            bool other_extends = false;
317	            for (auto& value : entry.second) {
318	                if (tmp.Ptr() == value)
319	                    continue;
320	
321	                art::ArtMethod method = value;
322	                art::mirror::Class clazz = method.GetDeclaringClass();
323	                art::mirror::Class clazz_super = clazz.GetSuperClass();
324	                art::mirror::Class thiz_super = thiz.GetSuperClass();
325	
326	                if (thiz_super.Ptr() != clazz_super.Ptr()) {
327	                    other_extends = true;
328	                    break;
329	                }
330	            }
331	
332	            if (other_extends) {
333	                bool other_super = false;
334	                for (auto& idx : super_methods) {
335	                    uint64_t tmp_super = FindSuperMethodToCall(tmp, idx);
336	                    for (auto& value : entry.second) {
337	                        if (tmp.Ptr() == value)
338	                            continue;
339	
340	                        art::ArtMethod method = value;
341	                        uint64_t method_super = FindSuperMethodToCall(method, idx);
342	
343	                        if (tmp_super != method_super) {
344	                            other_super = true;
345	                            break;
346	                        }
347	                    }
348	                }
349	
350	                if (other_super) {
351	                    uint64_t dex_pc_ptr = entry.first;
352	                    LOGE("verify class reuse dex_pc_ptr method\n");
353	                    for (auto& value : entry.second) {
354	                        art::ArtMethod method = value;
355	                        LOGI("[0x%" PRIx64 "] " ANSI_COLOR_LIGHTGREEN "%s" ANSI_COLOR_RESET "%s\n",
356	                                method.Ptr(), art::PrettyMethodAccessFlags(method.access_flags()).c_str(), method.ColorPrettyMethod().c_str());
357	                        for (auto& idx : super_methods) {
358	                            art::ArtMethod resolve_method = FindSuperMethodToCall(method, idx);
359	                            if (resolve_method.Ptr())
360	                                LOGD("    |--> invoke [0x%" PRIx64 "](%s)\n", resolve_method.Ptr(), resolve_method.ColorPrettyMethod().c_str());
361	                        }
362	                    }
363	                    ENTER();
364	                }
365	            }
366	        }
367	    }
368	}
