370	void JavaVerify::VerifyRecordClass(art::mirror::Class& clazz) {
371	    java::lang::Object thiz = clazz;
372	    if (clazz.IsRecordClass() || thiz.mirror_instanceof("java.lang.Record")) {
373	        std::string classname = clazz.PrettyDescriptor();
374	        if (classname != "java.lang.Record") {
375	            LOGE("verify class [0x%" PRIx64 "] extends java.lang.Record\n", clazz.Ptr());
376	            LOGI("Class Name: " ANSI_COLOR_LIGHTMAGENTA "%s\n" ANSI_COLOR_RESET, classname.c_str());
377	            ENTER();
378	        }
379	    }
380	}
