338	void Android::ForeachArtMethods(art::mirror::Class& clazz, std::function<bool (art::ArtMethod& method)> fn) {
339	    auto visit_methods_fn = [&](uint64_t methods, uint32_t size) {
340	        if (size) {
341	            api::MemoryRef base(methods, clazz);
342	            base.Prepare(false);
343	            int i = 0;
344	            do {
345	                art::ArtMethod method(base.Ptr() + i * SIZEOF(ArtMethod), base);
346	                if (fn(method)) break;
347	                i++;
348	            } while(i < size);
349	        }
350	    };
351	
352	    if (LIKELY(Sdk() >= N))
353	        visit_methods_fn(clazz.GetMethods(), clazz.NumMethods());
354	    else {
355	        visit_methods_fn(clazz.GetDirectMethods(), clazz.NumDirectMethods());
356	        visit_methods_fn(clazz.GetVirtualMethods(), clazz.NumVirtualMethods());
357	    }
358	}
