384	void Android::ForeachObjects(std::function<bool (art::mirror::Object& object)> fn, int flag, bool check) {
385	    art::Runtime& runtime = art::Runtime::Current();
386	    art::gc::Heap& heap = runtime.GetHeap();
387	
388	    auto walkfn = [&](art::gc::space::Space* space) {
389	        LOGD("Walk [%s] ...\n", space->GetName());
390	        try {
391	            if (space->IsVaildSpace()) {
392	                space->Walk(fn, check);
393	            } else {
394	                LOGE("%s invalid space.\n", space->GetName());
395	            }
396	        } catch (InvalidAddressException& e) {
397	            LOGW("Walk [%s] was interrupted!\n", space->GetName());
398	        }
399	    };
400	
401	    for (const auto& space : heap.GetContinuousSpaces()) {
402	        if (space->IsImageSpace()) {
403	            if (flag & EACH_IMAGE_OBJECTS) walkfn(space.get());
404	        } else if (space->IsZygoteSpace()) {
405	            if (flag & EACH_ZYGOTE_OBJECTS) walkfn(space.get());
406	        } else if (space->IsRegionSpace() || space->IsBumpPointerSpace()) {
407	            if (flag & EACH_APP_OBJECTS) walkfn(space.get());
408	        } else if (space->IsMallocSpace()) {
409	            if (space->IsRosAllocSpace()) {
410	                if (flag & EACH_APP_OBJECTS) walkfn(space.get());
411	            } else if (space->IsDlMallocSpace()) {
412	                if (flag & EACH_APP_OBJECTS) walkfn(space.get());
413	            }
414	        } else if (space->IsFakeSpace()) {
415	            if (flag & EACH_FAKE_OBJECTS) walkfn(space.get());
416	        } else {
417	            if (space->GetType() != art::gc::space::kSpaceTypeInvalidSpace) {
418	                walkfn(space.get());
419	            } else {
420	                LOGE("please run sysroot libart.so and run env art -c, %s invalid space.\n", space->GetName());
421	            }
422	        }
423	    }
424	
425	    for (const auto& space : heap.GetDiscontinuousSpaces()) {
426	        if (flag & EACH_APP_OBJECTS) walkfn(space.get());
427	    }
428	}
429	
430	void Android::ForeachReferences(std::function<bool (art::mirror::Object& object)> fn) {
431	    ForeachReferences(fn, EACH_LOCAL_REFERENCES | EACH_GLOBAL_REFERENCES | EACH_WEAK_GLOBAL_REFERENCES);
432	}
433	
434	void Android::ForeachReferences(std::function<bool (art::mirror::Object& object)> fn, int flag) {
435	    auto callback = [&](art::mirror::Object& object, int type, uint64_t idx) -> bool {
436	        fn(object);
437	        return false;
438	    };
439	    ForeachReferences(callback, flag);
440	}
441	
442	void Android::ForeachReferences(std::function<bool (art::mirror::Object& object, int type, uint64_t idx)> fn) {
443	    ForeachReferences(fn, EACH_LOCAL_REFERENCES | EACH_GLOBAL_REFERENCES | EACH_WEAK_GLOBAL_REFERENCES);
444	}
445	
446	void Android::ForeachReferences(std::function<bool (art::mirror::Object& object, int type, uint64_t idx)> fn, int flag) {
447	    art::Runtime& runtime = art::Runtime::Current();
448	    art::JavaVMExt& jvm = runtime.GetJavaVM();
449	
450	    int tid = flag >> EACH_LOCAL_REFERENCES_BY_TID_SHIFT;
451	    if (flag & EACH_LOCAL_REFERENCES) {
452	        art::ThreadList& thread_list = runtime.GetThreadList();
453	        for (const auto& thread : thread_list.GetList()) {
454	            int current = thread->GetTid();
455	            if (tid && tid != current || !current)
456	                continue;
457	
458	            auto local_fn = [&](art::mirror::Object& object, uint64_t idx) -> bool {
459	                fn(object, art::IndirectRefKind::kLocal | (current << EACH_LOCAL_REFERENCES_BY_TID_SHIFT), idx);
460	                return false;
461	            };
462	
463	            LOGD("Walk [%d] local references table\n", thread->GetTid());
464	            art::JNIEnvExt& jni_env = thread->GetJNIEnv();
465	            if (Sdk() >= U) {
466	                art::jni::LocalReferenceTable& local = jni_env.GetLocalsTable_v34();
467	                local.Walk(local_fn);
468	            } else {
469	                art::IndirectReferenceTable& local = jni_env.GetLocalsTable();
470	                local.Walk(local_fn);
471	            }
472	        }
473	    }
474	
475	    if (flag & EACH_GLOBAL_REFERENCES) {
476	        auto global_fn = [&](art::mirror::Object& object, uint64_t idx) -> bool {
477	            fn(object, art::IndirectRefKind::kGlobal, idx);
478	            return false;
479	        };
480	
481	        LOGD("Walk global references table\n");
482	        art::IndirectReferenceTable& global = jvm.GetGlobalsTable();
483	        global.Walk(global_fn);
484	    }
485	
486	    if (flag & EACH_WEAK_GLOBAL_REFERENCES) {
487	        auto weak_fn = [&](art::mirror::Object& object, uint64_t idx) -> bool {
488	            fn(object, art::IndirectRefKind::kWeakGlobal, idx);
489	            return false;
490	        };
491	
492	        LOGD("Walk weak global references table\n");
493	        art::IndirectReferenceTable& weak_global = jvm.GetWeakGlobalsTable();
494	        weak_global.Walk(weak_fn);
495	    }
496	}
497	
498	void Android::SysRoot(const char* path) {
499	    art::Runtime& runtime = art::Runtime::Current();
500	    if (!runtime.Ptr()) return;
501	
502	    std::vector<char *> dirs;
503	    std::unique_ptr<char[], void(*)(void*)> newpath(strdup(path), free);
504	    char *token = strtok(newpath.get(), ":");
505	    while (token != nullptr) {
506	        dirs.push_back(token);
507	        token = strtok(nullptr, ":");
508	    }
509	
510	    art::ClassLinker& linker = runtime.GetClassLinker();
511	    for (const auto& value : linker.GetDexCacheDatas()) {
512	        art::mirror::DexCache& dex_cache = value->GetDexCache();
513	        art::DexFile& dex_file = value->GetDexFile();
514	        std::string name;
515	        if (dex_cache.Ptr()) {
516	            name = dex_cache.GetLocation().ToModifiedUtf8();
517	        } else if (dex_file.Ptr()) {
518	            name = dex_file.GetLocation().c_str();
519	        }
520	        LoadBlock* block = CoreApi::FindLoadBlock(dex_file.data_begin(), false);
521	        if (block) {
522	            bool isVdex = false;
523	            art::OatDexFile& oat_dex_file = dex_file.GetOatDexFile();
524	            if (oat_dex_file.Ptr()) {
525	                art::OatFile& oat_file = oat_dex_file.GetOatFile();
526	                if (oat_file.Ptr() && block->virtualContains(oat_file.GetVdexBegin())) {
527	                    name = oat_file.GetVdexFile().GetName();
528	                    isVdex = true;
529	                }
530	            }
531	
532	            std::unique_ptr<char[], void(*)(void*)> newname(strdup(name.c_str()), free);
533	            char *ori_dex_file = strtok(newname.get(), "!");
534	            char *sub_file = strtok(NULL, "!");
535	
536	            std::string filepath;
537	            for (char *dir : dirs) {
538	                if (Utils::SearchFile(dir, &filepath, ori_dex_file))
539	                    break;
540	            }
541	
542	            if (!filepath.length())
543	                continue;
544	
545	            if (isVdex) {
546	                std::unique_ptr<MemoryMap> map(MemoryMap::MmapFile(filepath.c_str()));
547	                if (map) {
548	                    if (memcmp((void*)map->data(), "vdex", 4)) {
549	                        LOGE("Invalid vdex file (%s)\n", filepath.c_str());
550	                        continue;
551	                    }
552	                    block->setMmapFile(filepath.c_str(), 0x0);
553	                }
554	            } else {
555	                ZipFile zip;
556	                if (zip.open(filepath.c_str())) {
557	                    LOGE("Zip open fail [%" PRIx64 "]" ANSI_COLOR_LIGHTMAGENTA "%s\n" ANSI_COLOR_RESET, block->vaddr(), filepath.c_str());
558	                    continue;
559	                }
560	
561	                ZipEntry* entry;
562	                if (!sub_file) {
563	                    entry = zip.getEntryByName("classes.dex");
564	                } else {
565	                    entry = zip.getEntryByName(sub_file);
566	                }
567	
568	                if (!entry) {
569	                    LOGE("%s Not found entry" ANSI_COLOR_LIGHTMAGENTA "%s\n" ANSI_COLOR_RESET, filepath.c_str(), sub_file ? sub_file : "classes.dex");
570	                    continue;
571	                }
572	
573	                if (!entry->IsUncompressed()) {
574	                    LOGE("Not support compress zip [%" PRIx64 "] %s!%s\n", block->vaddr(), filepath.c_str(), sub_file ? sub_file : "classes.dex");
575	                    continue;
576	                }
577	
578	                block->setMmapFile(filepath.c_str(), RoundDown(entry->getFileOffset(), CoreApi::GetPageSize()));
579	            }
580	        } else {
581	            LOGE("Unknown DexCache(0x%" PRIx64 ") %s region\n", dex_cache.Ptr(), dex_cache.GetLocation().ToModifiedUtf8().c_str());
582	        }
583	    }
584	}
585	
586	void Android::Prepare() {
587	    try {
588	        if (!CoreApi::IsReady() || !IsSdkReady())
589	            return;
590	
591	        if (!INSTANCE->instance_.Ptr()) {
592	            art::Runtime& runtime = art::Runtime::Current();
593	            art::gc::Heap& heap = runtime.GetHeap();
594	            heap.GetContinuousSpaces();
595	            heap.GetDiscontinuousSpaces();
596	        }
597	    } catch (InvalidAddressException& e) {}
598	}
