213	void RegionSpace::WalkInternal(std::function<bool (mirror::Object& object)> visitor, bool only, bool check) {
214	    Region regions_(regions(), this);
215	    uint64_t num_regions_ = num_regions();
216	    for (int i = 0; i < num_regions_; ++i) {
217	        Region r(regions_.Ptr() + i * SIZEOF(Region), regions_);
218	        uint64_t pos = r.Begin();
219	        uint64_t top = r.Top();
220	
221	        if (r.IsFree() || (only && r.IsInToSpace()))
222	            continue;
223	
224	        if (r.IsLarge()) {
225	            mirror::Object object = r.Begin();
226	            if (object.GetClass().Ptr() != 0x0) {
227	                visitor(object);
228	            }
229	        } else if (r.IsLargeTail()) {
230	            // Do nothing.
231	        } else {
232	            try {
233	                WalkNonLargeRegion(visitor, r, check);
234	            } catch (InvalidAddressException& e) {
235	                LOGW("[0x%" PRIx64 "] Region:[0x%" PRIx64 ", 0x%" PRIx64 ") walkspace exception!\n", r.Ptr(), pos, top);
236	            }
237	        }
238	    }
239	}
