241	void RegionSpace::WalkNonLargeRegion(std::function<bool (mirror::Object& object)> visitor, RegionSpace::Region& region, bool check) {
242	    uint64_t pos = region.Begin();
243	    uint64_t begin = pos;
244	    uint64_t top = region.Top();
245	    mirror::Object object_cache = pos;
246	    object_cache.Prepare(false);
247	    uint64_t bit_mask = CoreApi::GetPointMask();
248	
249	    const bool need_bitmap =
250	        region.LiveBytes() != (static_cast<uint64_t>(-1) & bit_mask) &&
251	        region.LiveBytes() != static_cast<uint64_t>(top - pos);
252	
253	    if (need_bitmap) {
254	        GetLiveBitmap().VisitMarkedRange(pos, top, visitor, check);
255	    } else {
256	        while (pos < top) {
257	            mirror::Object object(pos, object_cache);
258	            if (object.IsNonLargeValid()) {
259	                visitor(object);
260	                pos = GetNextObject(object);
261	            } else {
262	                pos = object.NextValidOffset(top);
263	                if (check && pos < top) LOGE("Region:[0x%" PRIx64 ", 0x%" PRIx64 ") %s has bad object!!\n", object.Ptr(), pos, GetName());
264	            }
265	        }
266	    }
