69	void ContinuousSpaceBitmap::VisitMarkedRange(uint64_t visit_begin, uint64_t visit_end,
70	                                             std::function<bool (mirror::Object& object)> visitor, bool check) {
71	    api::MemoryRef bitmap_begin_ref(bitmap_begin());
72	    api::MemoryRef heap_begin_ref(heap_begin());
73	    heap_begin_ref.Prepare(false);
74	    int point_bit = CoreApi::GetPointSize();
75	
76	    uint64_t offset_start = visit_begin - heap_begin_ref.Ptr();
77	    uint64_t offset_end = visit_end - heap_begin_ref.Ptr();
78	
79	    uint64_t index_start = OffsetToIndex(offset_start, point_bit);
80	    uint64_t index_end = OffsetToIndex(offset_end, point_bit);
81	
82	    uint64_t bit_start = (offset_start / kObjectAlignment) % (kBitsPerByte * point_bit);
83	    uint64_t bit_end = (offset_end / kObjectAlignment) % (kBitsPerByte * point_bit);
84	
85	    // Index(begin)  ...    Index(end)
86	    // [xxxxx???][........][????yyyy]
87	    //      ^                   ^
88	    //      |                   #---- Bit of visit_end
89	    //      #---- Bit of visit_begin
90	    //
91	
92	    // Left edge.
93	    uint64_t left_edge = bitmap_begin_ref.valueOf((index_start * point_bit));
94	    // Mark of lower bits that are not in range.
95	    left_edge &= ~((static_cast<uint64_t>(1) << bit_start) - 1);
96	
97	    // Right edge. Either unique, or left_edge.
98	    uint64_t right_edge;
99	
100	    if (index_start < index_end) {
101	        // Left edge != right edge.
102	
103	        // Traverse left edge.
104	        if (left_edge != 0) {
105	            uint64_t ptr_base = IndexToOffset(index_start, point_bit) + heap_begin_ref.Ptr();
106	            do {
107	                uint64_t shift = __builtin_ctzll(left_edge);
108	                mirror::Object obj(ptr_base + shift * kObjectAlignment, heap_begin_ref);
109	                if (obj.IsNonLargeValid()) {
110	                    visitor(obj);
111	                } else if (check) {
112	                    LOGE("0x%" PRIx64 " is bad object on [0x%" PRIx64 ", 0x%" PRIx64 ").\n", obj.Ptr(), visit_begin, visit_end);
113	                }
114	                left_edge ^= ((static_cast<uint64_t>(1)) << shift);
115	            } while (left_edge != 0);
116	        }
117	
118	        // Traverse the middle, full part.
119	        for (uint64_t i = index_start + 1; i < index_end; ++i) {
120	            uint64_t w = bitmap_begin_ref.valueOf((i * point_bit));
121	            if (w != 0) {
122	                uint64_t ptr_base = IndexToOffset(i, point_bit) + heap_begin_ref.Ptr();
123	                // Iterate on the bits set in word `w`, from the least to the most significant bit.
124	                do {
125	                    uint64_t shift = __builtin_ctzll(w);
126	                    mirror::Object obj(ptr_base + shift * kObjectAlignment, heap_begin_ref);
127	                    if (obj.IsNonLargeValid()) {
128	                        visitor(obj);
129	                    } else if (check) {
130	                        LOGE("0x%" PRIx64 " is bad object on [0x%" PRIx64 ", 0x%" PRIx64 ").\n", obj.Ptr(), visit_begin, visit_end);
131	                    }
132	                    w ^= (static_cast<uint64_t>(1)) << shift;
133	                } while (w != 0);
134	            }
135	        }
136	
137	        // Right edge is unique.
138	        // But maybe we don't have anything to do: visit_end starts in a new word...
139	        if (bit_end == 0) {
140	            // Do not read memory, as it could be after the end of the bitmap.
141	            right_edge = 0;
142	        } else {
143	            right_edge = bitmap_begin_ref.valueOf((index_end * point_bit));
144	        }
145	    } else {
146	        // Right edge = left edge.
147	        right_edge = left_edge;
148	    }
149	
150	    // Right edge handling.
151	    right_edge &= ((static_cast<uint64_t>(1) << bit_end) - 1);
152	    if (right_edge != 0) {
153	        uint64_t ptr_base = IndexToOffset(index_end, point_bit) + heap_begin_ref.Ptr();
154	        // Iterate on the bits set in word `right_edge`, from the least to the most significant bit.
155	        do {
156	            uint64_t shift = __builtin_ctzll(right_edge);
157	            mirror::Object obj(ptr_base + shift * kObjectAlignment, heap_begin_ref);
158	            if (obj.IsNonLargeValid()) {
